INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(63, 'Tajanay', 100, 'tajanayarmani98@icloud.com', 'BMI Candidate Requirements', 'Do you have a BMI requirement?', 'Dr. Nandi Wijay', 'Do we have a BMI requirement for Tummy Tuck!', '<p><span style="font-family: ''Segoe UI'', sans-serif; color: black; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">Great Question!&nbsp; </span></p>\r\n<p><span style="font-family: ''Segoe UI'', sans-serif; color: black; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">A lot of patients have this question when they come in for a consultation.</span><span style="font-family: ''&amp;quot'',serif; color: black;"><br style="-webkit-text-stroke-width: 0px; word-spacing: 0px;" /></span><span style="font-family: ''Segoe UI'', sans-serif; color: black; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="orphans: 2; -webkit-text-stroke-width: 0px; cursor: text; float: none; word-spacing: 0px;">First, BMI is a great tool doctors can use to help determine a patient&rsquo;s general body type.&nbsp; However, BMI does not completely determine if a patient is healthy enough to undergo surgery and anesthesia. &nbsp;</span></span><span style="font-family: ''&amp;quot'',serif; color: black;"><br style="-webkit-text-stroke-width: 0px; word-spacing: 0px;" /></span><span style="font-family: ''Segoe UI'', sans-serif; color: black; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="orphans: 2; -webkit-text-stroke-width: 0px; cursor: text; float: none; word-spacing: 0px;">When a patient comes in for a consultation, we will take a detailed history and physical to determine if they are a good candidate for surgery.&nbsp;</span></span><span style="font-family: ''&amp;quot'',serif; color: black;"><br style="-webkit-text-stroke-width: 0px; word-spacing: 0px;" /></span><span style="font-family: ''Segoe UI'', sans-serif; color: black; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><span style="orphans: 2; -webkit-text-stroke-width: 0px; cursor: text; float: none; word-spacing: 0px;">So, we do not have a strict BMI cutoff, but as your BMI goes above 30 we take extra precautions and more pre-operative testing before we preforming surgery!</span></span></p>', 'Tummy Tuck', '[null,null,null]', 1, 0, '2020-01-22');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(64, 'FAQ', 100, 'info@theoaksplasticsurgery.com', 'How long does it take to recover from a tummy tuck?', 'A very common question from our patients!\r\nHow long does it take to recover from a tummy tuck?', 'Dr. Nandi Wijay', 'How long does it take to recover from a tummy tuck?', '<p>Very common and important question!</p>\r\n<p>Two very important things to know first is that every patient is different and that there are different types of Tummy Tucks.&nbsp; Most patients can expect about 2 weeks of no heavy lifting after surgery. During those two weeks patients will be bent over and will slowly straighten up over a 2 weeks span.&nbsp; Also, most of our&nbsp;patients who receive a Tummy Tucks in Houston will also have a muscle repair at the same time.&nbsp; Patients who need a larger repair will have a slightly longer recovery.&nbsp; At The Oaks Plastic Surgery we can use a special medication called Exparel that can help pain control for the first 3 days after surgery. After 2 weeks our patient start resuming their normal daily activity.&nbsp; At the 6 weeks mark most patients will have a full release to exercise.&nbsp;</p>', 'Tummy Tuck', '[null,null,null]', 1, 0, '2020-01-27');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(66, 'Info', 100, 'INFO@THEOAKSPLASTICSURGERY.COM', 'How much is a breast augmentation in Houston?', 'How much is a breast augmentation in Houston?', 'Dr. Nandi Wijay', 'How much is a breast augmentation in Houston?', '<p>The answer will vary depending on a couple of factors. Are you looking for silicone or Saline? Do we need to remove a previous implant? Where you able to lock in special pricing? We also factor in anesthesia costs, surgeons'' fees, and facility fees. At The Oaks Plastic Surgery, breast augmentations typical cost in the range of $5000-6500. Our Patient Coordinator will give you a specific cost depending on your unique treatment plan.</p>\r\n<p>&nbsp;</p>', 'Breast Augmentation', '[null,null,null]', 1, 0, '2020-01-27');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(67, 'Mavi', 100, 'INFO@THEOAKSPLASTICSURGERY.COM', 'How much would it cost to get breast implants?', 'How much would it cost to get breast implants?', 'Dr. Danielle Andry', 'Pricing', '<p>The answer will vary depending on a couple of factors. Are you looking for silicone or Saline? Do we need to remove a previous implant? Will a revision be needed that requires extra OR time? Where you able to lock in special pricing? We also factor in anesthesia costs, surgeons'' fees, and facility fees. At The Oaks Plastic Surgery, breast augmentations typical cost in the range of $5000-6500. Our Patient Coordinator will give you a specific cost depending on your unique treatment plan.</p>', 'Breast Augmentation', '[null,null,null]', 1, 0, '2020-01-27');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(68, 'mavi', 100, 'INFO@THEOAKSPLASTICSURGERY.COM', 'What are gummy bear implants?', 'What are gummy bear implants?', 'Dr. Nandi Wijay', 'Gummy Implants', '<p>The Gummy implants are made of silicone gel. This gummy-like gel sticks together and holds its shape. They are very soft to the touch and you can choose from a couple of levels of gummy to gummiest. Gummy implants are made with state-of-the-art breast implant shell that is designed to keep the gel inside.&nbsp;</p>', 'Breast Augmentation', '[null,null,null]', 0, 0, '2020-01-27');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(69, 'Mavi', 100, 'INFO@THEOAKSPLASTICSURGERY.COM', 'Do breast implants sag over time?', 'Do breast implants sag over time?', 'Dr. Nandi Wijay', 'Do breast implants sag over time?', '<p>Because the implant helps hold the breast up, it prolongs the sagging process. Every patient has a different skin quality and laxity so that will determine how time will work in your favor.&nbsp;</p>', 'Breast Augmentation', '[null,null,null]', 1, 0, '2020-01-27');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(70, 'Info', 100, 'INFO@THEOAKSPLASTICSURGERY.COM', 'How long does it take to recover from a tummy tuck?', 'How long does it take to recover from a tummy tuck?', 'Dr. Danielle Andry', 'Pricing', '<p>Very common and important question!</p>\r\n<p>Two very important things to know first is that every patient is different and that there are different types of Tummy Tucks.&nbsp; Most patients can expect about 2 weeks of no heavy lifting after surgery. During those two weeks, patients will be bent over and will slowly straighten up over a 2 weeks span.&nbsp; Also, most of our patients who receive a Tummy Tucks in Houston will also have a muscle repair at the same time.&nbsp; Patients who need a larger repair will have a slightly longer recovery.&nbsp; At The Oaks Plastic Surgery, we can use a special medication called Exparel that can help pain control for the first 3 days after surgery. After 2 weeks our patient starts resuming their normal daily activity.&nbsp; At the 6 weeks mark most patients will have a full release to exercise.&nbsp;</p>', 'Tummy Tuck', '[null,null,null]', 1, 0, '2020-01-27');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(71, 'Mavi', 100, 'INFO@THEOAKSPLASTICSURGERY.COM', 'How much is a tummy tuck in Houston?', 'How much is a tummy tuck in Houston?', 'Dr. Nandi Wijay', 'Pricing', '<p>Also depending on each patient and the complexity of their case, tummy tucks range from 7,500-9,500. That is including anesthesia fees, surgeons fees, and facility fees. We also include your first garment, a nurse visit after the surgery and a massage therapist for a 1-hour lymphatic massage. All your pre and post-operative visits are also included in the price.</p>', 'Mommy Makeover', '[null,null,null]', 1, 0, '2020-01-27');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(72, 'Mavi', 100, 'INFO@THEOAKSPLASTICSURGERY.COM', 'How long does it take to recover from a tummy tuck?', 'How long does it take to recover from a tummy tuck?', 'Dr. Nandi Wijay', 'Pricing', '<p>Very common and important question!</p>\r\n<p>Two very important things to know first is that every patient is different and that there are different types of Tummy Tucks.&nbsp; Most patients can expect about 2 weeks of no heavy lifting after surgery. During those two weeks patients will be bent over and will slowly straighten up over a 2 weeks span.&nbsp; Also, most of our&nbsp;patients who receive a Tummy Tucks in Houston will also have a muscle repair at the same time.&nbsp; Patients who need a larger repair will have a slightly longer recovery.&nbsp; At The Oaks Plastic Surgery we can use a special medication called Exparel that can help pain control for the first 3 days after surgery. After 2 weeks our patient start resuming their normal daily activity.&nbsp; At the 6 weeks mark most patients will have a full release to exercise.&nbsp;</p>', 'Tummy Tuck', '[null,null,null]', 1, 0, '2020-01-27');
