(78, 'Christine Ahn', 100, 'somsmom@gmail.com', 'Rhinoplasty', 'Â­ Â â£Greetings. I am inquiring about rhinoplasty/ tip plasty. I have a deviated septum that was supposed to be treated by an ENT prior to the pandemic. It was supposed to be fully covered by insurance in my home state of Illinois but I recently moved to Houston and am looking to get it fixed here and also correct the tip cosmetically at the same time. Do you do this procedure and could you give me a ballpark estimate of how much I would have to pay out of pocket?', '', '', '', 'Rhinoplasty', '[null,null,null]', 0, 0, '2020-06-15');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
