INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(80, 'Tameka', 100, 'tamekadmartin@gmail.com', 'Pricing', 'Inquiring about the price of this service?', 'Dr. Nandi Wijay', 'Breast Reduction Price', '<p>Price for a Breast Reduction depends on time!&nbsp; ranges from 6,500 to 9,000.&nbsp; If the breast are very large, insurance can sometimes cover the procedure.</p>', 'Breast Reduction', '[null,null,null]', 1, 0, '2020-08-14');
