INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(83, NULL, 100, NULL, 'What do you recommend?', 'I had a breast lift and reduction in 2018. I went from a DDD to a B. I don''t like that my breast are flat and disappear when I raise my arms or lie flat. I had a tummy tuck in 2016 and shortly after my stomach started to protrude out. What do you recommend for a flat stomach and breast that are round with a high profile? What is the cost?', 'Dr. Nandi Wijay', 'Breast and Tummy Tuck Question', '<p>Thank you for your question!&nbsp; We would defintely need to examine your breast to know exactly what to do.&nbsp; There are a couple of ways to help this concern, first possibly a breast implant can help with the shape or possibly some special breast surgery techniques can help give the breast more shape.&nbsp; &nbsp;in regards to your stomach the two options are liposuction or to complete a tummy tuck again.</p>', 'Mommy Makeover', '[null,null,null]', 1, 0, '2020-08-14');
