INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(162, NULL, 100, NULL, 'Inquiry', 'Hi. My name is Aaron. I am looking into breast/hip implants. First, I wanted to ask if you discriminate against male patients. I am biologically male. Some providers refuse treatment to male patients unless they go on estrogen. I am not on estrogen nor do I intend to start cross sex hormones. As an adult of sound mind, I am competent to make decisions regarding my own body and health, and I would appreciate not being discriminated on the basis of my sex (male) or gender identity (transfeminine). If you don''t discriminate on the basis of biological sex or gender identity, I would like to know cost and get more info please. But I don''t want to waste my time coming in for a consultation just to be told that you won''t perform a cosmetic procedure on me because I''m male and choose not to take hormones. So please let me know. I prefer to be contacted by email initially. Thanks.', '', '', '', 'Breast Augmentation', '[null,null,null]', 0, 0, '2025-03-01');
INSERT INTO forum_questions (id, name, sort, email, question_subject, question, doctor, answer_subject, answer, service, images, approved, is_read, created_at) VALUES
(163, NULL, 100, NULL, 'male breast implants', 'Hi. My name is Aaron. I am looking into breast/hip implants. First, I wanted to ask if you discriminate against male patients. I am biologically male. Some providers refuse treatment to male patients unless they go on estrogen. I am not on estrogen nor do I intend to start cross sex hormones. As an adult of sound mind, I am competent to make decisions regarding my own body and health, and I would appreciate not being discriminated on the basis of my sex (male) or gender identity (transfeminine). If you don''t discriminate on the basis of biological sex or gender identity, I would like to know cost and get more info please. But I don''t want to waste my time coming in for a consultation just to be told that you won''t perform a cosmetic procedure on me because I''m male and choose not to take hormones. So please let me know. I prefer to be contacted by email initially. Thanks.', '', '', '', 'Breast Augmentation', '[null,null,null]', 0, 0, '2025-03-01');
